// Parse each Google Calendar event and build the upsert SQL inline.
// Embedding values directly avoids n8n queryReplacement quirks.

function esc(v) {
  // Escape a value for safe inclusion in a SQL string literal.
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}

function stripHtml(html) {
  if (!html) return null;
  return html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim() || null;
}

const items = $input.all();
const results = [];

for (const item of items) {
  const ev = item.json;

  // Skip all-day events (no dateTime) and untitled events
  if (!ev.start?.dateTime) continue;
  const title = (ev.summary || '').trim();
  if (!title) continue;

  const description = stripHtml(ev.description);
  const titleLower = title.toLowerCase();
  // Use raw description for tag/ticket parsing before HTML is stripped from those lines
  const rawDesc = (ev.description || '');

  // Auto-detect tag from title
  let tag = null;
  if (titleLower.includes('final friday')) {
    tag = 'final-friday';
  } else if (titleLower.includes('open house') || titleLower.includes('ohc')) {
    tag = 'ohc';
  } else if (titleLower.includes('instant noodles') || titleLower.includes('community jam')) {
    tag = 'community-jam';
  } else if (titleLower.includes('art walk') || titleLower.includes('second saturday') || titleLower.includes('2nd saturday')) {
    tag = 'art-walk';
  } else if (titleLower.includes('workshop') || titleLower.includes('class')) {
    tag = 'workshop-class';
  } else {
    const tagsMatch = rawDesc.match(/^tags:\s*(.+)$/im);
    if (tagsMatch) tag = tagsMatch[1].trim().split(',')[0].trim();
  }

  // Parse tickets: url from raw description
  let ticketUrl = null;
  const ticketsMatch = rawDesc.match(/^tickets:\s*(https?:\/\/\S+)$/im);
  if (ticketsMatch) ticketUrl = ticketsMatch[1].trim();

  const googleEventId = ev.id;
  const startTime = ev.start.dateTime;
  const endTime = ev.end?.dateTime || null;
  const location = ev.location || null;
  const desc = description;

  const sql = `
INSERT INTO events (
  google_event_id, title, description, start_time, end_time,
  location, tag, ticket_url, is_active, synced_at
) VALUES (
  ${esc(googleEventId)}, ${esc(title)}, ${esc(desc)},
  ${esc(startTime)}::TIMESTAMPTZ, ${esc(endTime) === 'NULL' ? 'NULL' : esc(endTime) + '::TIMESTAMPTZ'},
  ${esc(location)}, ${esc(tag)}, ${esc(ticketUrl)}, true, NOW()
)
ON CONFLICT (google_event_id) DO UPDATE SET
  title       = EXCLUDED.title,
  description = EXCLUDED.description,
  start_time  = EXCLUDED.start_time,
  end_time    = EXCLUDED.end_time,
  location    = EXCLUDED.location,
  tag         = EXCLUDED.tag,
  ticket_url  = EXCLUDED.ticket_url,
  is_active   = true,
  synced_at   = NOW()
RETURNING id, google_event_id, title
`.trim();

  results.push({ json: { sql, title, tag } });
}

return results;
